import requests
from bs4 import BeautifulSoup

def fetch_page(url):
    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36'
    }

    # Check robots.txt
    robots_url = f"{url}/robots.txt"
    try:
        response = requests.get(robots_url)
        if 'Disallow' in response.text and '/careers/' in response.text:
            print("This site disallows scraping of the careers page. Exiting.")
            return None
    except Exception as e:
        print(f"Failed to check robots.txt: {e}")

    try:
        response = requests.get(url, headers=headers)
        if response.status_code == 200:
            return BeautifulSoup(response.text, 'html.parser')
        else:
            print("Failed to retrieve the page.")
            return None
    except Exception as e:
        print(f"An error occurred: {e}")
        return None

def extract_job_listings(soup):
    job_list = []

    # Example selector for jobs (you need to adjust this based on actual HTML structure)
    job_elements = soup.select('.job-listing a')

    for element in job_elements:
        title = element.get_text(strip=True)
        link = element['href']

        if not link.startswith('http'):
            link = url + link

        job_list.append({
            'title': title,
            'link': link
        })

    return job_list

def main():
    url = "https://example.com/careers"  # Replace with the actual URL of the careers page

    soup = fetch_page(url)
    if soup:
        jobs = extract_job_listings(soup)

        for job in jobs:
            print(f"{job['title']} - {job['link']}")

if __name__ == "__main__":
    main()
```

### Notes
- **Customization Required**: You need to adjust the `url` variable and the CSS selector (`soup.select('.job-listing a')`) according to the actual structure of the target website.
- **Pagination Handling**: If jobs are spread across multiple pages, you'll need to add logic to handle pagination (e.g., iterating through URLs like `/careers/page/2`, etc.).
- **Error Handling & Logging**: This example includes basic error handling and logging for simplicity. Depending on your needs, consider adding more robust error handling and logging mechanisms.

