import csv
from datetime import datetime
import re

def normalize_date(date_str):
    # Try different date formats
    date_formats = [
        '%m/%d/%Y',  # MM/DD/YYYY
        '%Y-%m-%d',  # YYYY-MM-DD
        '%B %d, %Y'  # January 5, 2024
    ]

    for fmt in date_formats:
        try:
            return datetime.strptime(date_str, fmt).isoformat()
        except ValueError:
            continue

    raise ValueError(f"Date format not recognized: {date_str}")

def normalize_price(price_str):
    # Remove currency symbols and commas
    price_str = re.sub(r'[^\d.,]', '', price_str)

    if ',' in price_str:
        # Convert European decimal separator to dot
        price_str = price_str.replace(',', '.')

    try:
        return float(price_str)
    except ValueError:
        raise ValueError(f"Price format not recognized: {price_str}")

def read_and_normalize_csv(file_path):
    with open(file_path, 'r', encoding='utf-8') as csvfile:
        reader = csv.reader(csvfile, delimiter=';', quotechar='"')

        # Read the header
        headers = next(reader)

        # Process each row
        normalized_data = []
        for row in reader:
            try:
                normalized_row = {}
                for i, value in enumerate(row):
                    if headers[i] == 'date':
                        normalized_row[headers[i]] = normalize_date(value)
                    elif headers[i] == 'price':
                        normalized_row[headers[i]] = normalize_price(value)
                    else:
                        normalized_row[headers[i]] = value
                normalized_data.append(normalized_row)
            except Exception as e:
                print(f"Error processing row: {row}. Error: {e}")

    return headers, normalized_data

def write_normalized_csv(headers, data, output_file):
    with open(output_file, 'w', newline='', encoding='utf-8') as csvfile:
        writer = csv.DictWriter(csvfile, fieldnames=headers)

        # Write the header
        writer.writeheader()

        # Write each row
        for row in data:
            try:
                writer.writerow(row)
            except Exception as e:
                print(f"Error writing row: {row}. Error: {e}")

if __name__ == "__main__":
